#!/usr/bin/env python3
# This file was generated by Cursor AI on 2026-05-02.
"""
Build virtual-best JSONs by metric.

For each benchmark path and each metric below, pick the stats dict from whichever source
run yields the largest decrease relative to control (control_metric - run_metric). Tie-break
by source JSON basename:
  - scq -> virtual_best_scq.json
  - num-tl-instructions -> virtual_best_num_tl_instructions.json
  - num-tl-temporal-instructions -> virtual_best_num_tl_temporal_instructions.json
  - sabre-total-bytes -> virtual_best_sabre_total_bytes.json

Default output directory is RESULTS_DIR. ``control.json`` must exist to define
the baseline; any of the run JSONs may be absent—virtual-best is computed from
whichever source files are present.
"""

from __future__ import annotations

import argparse
import copy
import json
import sys
from pathlib import Path
from typing import Any

SOURCE_RESULT_JSON = (
    "control.json",
    "greedy_ac.json",
    "greedy_no_ac.json",
    "ilp_ac.json",
    "ilp_no_ac.json",
)

VIRTUAL_BEST_BASENAME = "virtual_best_scq.json"
VIRTUAL_BEST_ENTRY_KEY = "virtual-best"
VIRTUAL_BEST_METRIC_TO_BASENAME = {
    "scq": "virtual_best_scq.json",
    "num-tl-instructions": "virtual_best_num_tl_instructions.json",
    "num-tl-temporal-instructions": "virtual_best_num_tl_temporal_instructions.json",
    "sabre-total-bytes": "virtual_best_sabre_total_bytes.json",
}

# Avoid repeating the same missing-file line when this module computes several metrics in one run.
_MISSING_SOURCES_NOTIFIED: set[str] = set()


def is_numeric(x: Any) -> bool:
    return isinstance(x, (int, float)) and not isinstance(x, bool)


def extract_stats_blob(entry: dict[str, Any]) -> dict[str, Any]:
    blobs = [
        v
        for k, v in entry.items()
        if k != "filename" and isinstance(v, dict)
    ]
    if not blobs:
        return {}
    if len(blobs) > 1:
        merged: dict[str, Any] = {}
        for b in blobs:
            merged.update(b)
        return merged
    return blobs[0]


def load_by_filename(path: Path) -> dict[str, dict[str, Any]]:
    data = json.loads(path.read_text(encoding="utf-8"))
    out: dict[str, dict[str, Any]] = {}
    for entry in data.get("results", []):
        fn = entry.get("filename")
        if not fn:
            continue
        stats = extract_stats_blob(entry)
        if stats:
            out[str(fn)] = stats
    return out


def compute_virtual_best(results_dir: Path, metric: str = "scq") -> dict[str, Any] | None:
    """
    For each filename appearing in control + source runs, choose the stats blob from the run
    with the largest reduction for `metric`: control_metric - run_metric.
    Runs missing numeric metric (or missing numeric control metric for that filename) are
    skipped for that filename.

    Returns None if ``control.json`` is missing (baseline required). Missing run
    JSONs under ``SOURCE_RESULT_JSON`` are skipped with a stderr notice.
    """
    results_dir = results_dir.resolve()
    control_path = results_dir / "control.json"
    if not control_path.is_file():
        print(
            "virtual_best: missing control.json; cannot compute virtual-best.",
            file=sys.stderr,
        )
        return None
    control_by_fn = load_by_filename(control_path)
    per_file: dict[str, list[tuple[float, str, dict[str, Any]]]] = {}
    missing_sources: list[str] = []
    for basename in SOURCE_RESULT_JSON:
        path = results_dir / basename
        if not path.is_file():
            missing_sources.append(basename)
            continue
        by_fn = load_by_filename(path)
        for fn, stats in by_fn.items():
            cstats = control_by_fn.get(fn, {})
            cval = cstats.get(metric)
            rval = stats.get(metric)
            if not is_numeric(cval) or not is_numeric(rval):
                continue
            reduction = float(cval or 0) - float(rval or 0)
            per_file.setdefault(fn, []).append(
                (reduction, basename, copy.deepcopy(stats))
            )

    if missing_sources:
        note_key = str(results_dir)
        if note_key not in _MISSING_SOURCES_NOTIFIED:
            print(
                "virtual_best: skipping missing source file(s): "
                + ", ".join(missing_sources),
                file=sys.stderr,
            )
            _MISSING_SOURCES_NOTIFIED.add(note_key)

    merged_results: list[dict[str, Any]] = []
    for fn in sorted(per_file.keys()):
        candidates = per_file[fn]
        if not candidates:
            continue
        _reduction, _src, best_stats = max(candidates, key=lambda t: (t[0], t[1]))
        merged_results.append(
            {"filename": fn, VIRTUAL_BEST_ENTRY_KEY: best_stats}
        )

    return {"results": merged_results}


def write_virtual_best(
    results_dir: Path,
    output_basename: str | None = None,
    *,
    output_path: Path | None = None,
) -> Path | None:
    """
    Write scq-based virtual best JSON. Returns output path, or None if the baseline
    is missing, the payload could not be computed, or the output file could not be written.
    """
    results_dir = results_dir.resolve()
    if output_path is not None:
        out_path = Path(output_path).expanduser().resolve()
    else:
        out_name = output_basename or VIRTUAL_BEST_BASENAME
        out_path = results_dir / out_name
    payload = compute_virtual_best(results_dir, metric="scq")
    if payload is None:
        return None
    try:
        out_path.write_text(json.dumps(payload, indent=2) + "\n", encoding="utf-8")
    except PermissionError as e:
        print(
            f"virtual_best: permission denied writing {out_path} ({e}).\n"
            "Use --output PATH to write somewhere writable, or fix ownership "
            f"(e.g. sudo chown $USER {out_path}).",
            file=sys.stderr,
        )
        return None
    return out_path


def write_virtual_best_per_metric(results_dir: Path) -> dict[str, Path]:
    """
    Write one virtual-best JSON per metric in VIRTUAL_BEST_METRIC_TO_BASENAME.
    Returns metric -> output path for files successfully written.
    """
    results_dir = results_dir.resolve()
    written: dict[str, Path] = {}
    for metric, basename in VIRTUAL_BEST_METRIC_TO_BASENAME.items():
        out_path = results_dir / basename
        payload = compute_virtual_best(results_dir, metric=metric)
        if payload is None:
            continue
        try:
            out_path.write_text(json.dumps(payload, indent=2) + "\n", encoding="utf-8")
        except PermissionError as e:
            print(
                f"virtual_best: permission denied writing {out_path} ({e}).",
                file=sys.stderr,
            )
            continue
        written[metric] = out_path
    return written


def main() -> int:
    script_dir = Path(__file__).resolve().parent
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument(
        "results_dir",
        nargs="?",
        type=Path,
        default=script_dir / "results",
        help="Directory containing control.json and run JSON files",
    )
    args = parser.parse_args()
    results_dir = args.results_dir.resolve()
    if not results_dir.is_dir():
        print(f"Not a directory: {results_dir}", file=sys.stderr)
        return 1
    written = write_virtual_best_per_metric(results_dir)
    if not written:
        print(
            "virtual_best: no metric outputs written (missing control.json or "
            "permission errors); see messages above.",
            file=sys.stderr,
        )
    else:
        for metric in sorted(written.keys()):
            print(f"Wrote {metric}: {written[metric]}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
